-- Custom notification queries (hand-written, not generated by pgtempl)

-- name: ListNotificationByAccount :many
SELECT sqlc.embed(n), COUNT(*) OVER() as total_count
FROM "account"."notification" n
WHERE n.account_id = @account_id
ORDER BY n.date_created DESC
LIMIT sqlc.narg('limit')::int
OFFSET sqlc.narg('offset')::int;

-- name: CountUnreadByAccount :one
SELECT COUNT(*)
FROM "account"."notification"
WHERE account_id = @account_id AND is_read = false;

-- name: MarkNotificationRead :exec
UPDATE "account"."notification"
SET is_read = true, date_updated = NOW()
WHERE id = ANY(sqlc.slice('id')) AND account_id = @account_id AND is_read = false;

-- name: MarkAllNotificationRead :exec
UPDATE "account"."notification"
SET is_read = true, date_updated = NOW()
WHERE account_id = @account_id AND is_read = false;
